struct CopyProgressShared {
    total_units: usize,
    total_items: usize,
    done_units: AtomicUsize,
    done_items: AtomicUsize,
    cancel_requested: AtomicBool,
}

impl CopyProgressShared {
    fn new(total_units: usize, total_items: usize) -> Self {
        Self {
            total_units: total_units.max(1),
            total_items: total_items.max(1),
            done_units: AtomicUsize::new(0),
            done_items: AtomicUsize::new(0),
            cancel_requested: AtomicBool::new(false),
        }
    }

    fn request_cancel(&self) {
        self.cancel_requested.store(true, Ordering::SeqCst);
    }

    fn cancelled(&self) -> bool {
        self.cancel_requested.load(Ordering::SeqCst)
    }

    fn advance_units(&self, units: usize) {
        if units == 0 {
            return;
        }
        self.done_units.fetch_add(units, Ordering::SeqCst);
    }

    fn advance_items(&self, items: usize) {
        if items == 0 {
            return;
        }
        self.done_items.fetch_add(items, Ordering::SeqCst);
    }

    fn snapshot(&self) -> (usize, usize, usize, usize) {
        (
            self.done_units.load(Ordering::SeqCst),
            self.done_items.load(Ordering::SeqCst),
            self.total_units,
            self.total_items,
        )
    }
}

