    fn draw_notepad_save_prompt(&mut self) {
        let Some(prompt) = self.notepad_save_prompt.as_ref() else {
            return;
        };
        let rect = self.notepad_save_prompt_rect();
        let (title, subtitle, instruction, ok_label) = match prompt.kind {
            SavePromptKind::Notepad => (
                "Guardar nota",
                "Arbol de unidades y carpetas:",
                "Click: seleccionar/expandir  A/D: cerrar/abrir  Enter: guardar",
                "OK",
            ),
            SavePromptKind::IdeExport => (
                "Exportar paquete IDE",
                "Selecciona carpeta destino:",
                "Click: seleccionar/expandir  A/D: cerrar/abrir  Enter: exportar",
                "Export",
            ),
            SavePromptKind::IdeLoad => (
                "Cargar proyecto IDE",
                "Selecciona carpeta fuente:",
                "Click: seleccionar/expandir  A/D: cerrar/abrir  Enter: cargar",
                "Load",
            ),
        };

        framebuffer::rect(
            rect.x.max(0) as usize,
            rect.y.max(0) as usize,
            rect.width as usize,
            rect.height as usize,
            0x10283A,
        );
        framebuffer::rect(
            rect.x.max(0) as usize,
            rect.y.max(0) as usize,
            rect.width as usize,
            1,
            0x7BB9E3,
        );
        framebuffer::rect(
            rect.x.max(0) as usize,
            (rect.y + rect.height as i32 - 1).max(0) as usize,
            rect.width as usize,
            1,
            0x091521,
        );

        framebuffer::draw_text_5x7(
            (rect.x + 10).max(0) as usize,
            (rect.y + 12).max(0) as usize,
            title,
            0xEAF6FF,
        );
        framebuffer::draw_text_5x7(
            (rect.x + 10).max(0) as usize,
            (rect.y + 28).max(0) as usize,
            subtitle,
            0xA6C7E1,
        );

        let list_rect = self.notepad_save_prompt_list_rect();
        framebuffer::rect(
            list_rect.x.max(0) as usize,
            list_rect.y.max(0) as usize,
            list_rect.width as usize,
            list_rect.height as usize,
            0x0A1C2B,
        );
        framebuffer::rect(
            list_rect.x.max(0) as usize,
            list_rect.y.max(0) as usize,
            list_rect.width as usize,
            1,
            0x4F7A9D,
        );
        framebuffer::rect(
            list_rect.x.max(0) as usize,
            (list_rect.y + list_rect.height as i32 - 1).max(0) as usize,
            list_rect.width as usize,
            1,
            0x0A1520,
        );

        let visible = self.notepad_save_prompt_visible_item_count();
        let visible_indices = Self::notepad_prompt_visible_indices(prompt);
        for row in 0..visible {
            let visible_pos = prompt.scroll_top.saturating_add(row);
            let Some(idx) = visible_indices.get(visible_pos).copied() else {
                break;
            };
            let Some(loc) = prompt.locations.get(idx) else {
                break;
            };
            let item_rect = self.notepad_save_prompt_item_rect(row);
            let selected = idx == prompt.selected_index;
            framebuffer::rect(
                item_rect.x.max(0) as usize,
                item_rect.y.max(0) as usize,
                item_rect.width as usize,
                item_rect.height as usize,
                if selected { 0x1A4F78 } else { 0x10273A },
            );
            framebuffer::rect(
                item_rect.x.max(0) as usize,
                item_rect.y.max(0) as usize,
                item_rect.width as usize,
                1,
                if selected { 0x8CC8F0 } else { 0x27445B },
            );

            let toggle_rect = self.notepad_save_prompt_toggle_rect(item_rect, loc.depth);
            if loc.has_children {
                framebuffer::rect(
                    toggle_rect.x.max(0) as usize,
                    toggle_rect.y.max(0) as usize,
                    toggle_rect.width as usize,
                    toggle_rect.height as usize,
                    if selected { 0x2A628C } else { 0x1A3347 },
                );
                framebuffer::rect(
                    (toggle_rect.x + 1).max(0) as usize,
                    (toggle_rect.y + 3).max(0) as usize,
                    6,
                    1,
                    0xD7ECFF,
                );
                if !loc.expanded {
                    framebuffer::rect(
                        (toggle_rect.x + 3).max(0) as usize,
                        (toggle_rect.y + 1).max(0) as usize,
                        1,
                        6,
                        0xD7ECFF,
                    );
                }
            }

            let icon_x = if loc.has_children {
                toggle_rect.x + toggle_rect.width as i32 + 4
            } else {
                toggle_rect.x + 2
            };
            if loc.is_unit {
                framebuffer::rect(
                    icon_x.max(0) as usize,
                    (item_rect.y + 5).max(0) as usize,
                    12,
                    8,
                    0xB4C5D6,
                );
                framebuffer::rect(
                    (icon_x + 2).max(0) as usize,
                    (item_rect.y + 7).max(0) as usize,
                    8,
                    3,
                    0xE6EEF6,
                );
            } else {
                framebuffer::rect(
                    icon_x.max(0) as usize,
                    (item_rect.y + 7).max(0) as usize,
                    12,
                    8,
                    0xE8C56B,
                );
                framebuffer::rect(
                    (icon_x + 2).max(0) as usize,
                    (item_rect.y + 5).max(0) as usize,
                    5,
                    3,
                    0xF2D78A,
                );
            }

            let item_text = loc.label.as_str();
            framebuffer::draw_text_5x7(
                (icon_x + 16).max(0) as usize,
                (item_rect.y + 7).max(0) as usize,
                Self::trim_ascii_line(item_text, 40).as_str(),
                if selected { 0xF2FAFF } else { 0xD3E8F8 },
            );
        }

        let selected_visible_row = visible_indices
            .iter()
            .position(|idx| *idx == prompt.selected_index)
            .map(|v| v + 1)
            .unwrap_or(0);
        let count_text = alloc::format!(
            "{}/{}",
            selected_visible_row,
            visible_indices.len()
        );
        framebuffer::draw_text_5x7(
            (rect.x + rect.width as i32 - 56).max(0) as usize,
            (rect.y + 28).max(0) as usize,
            count_text.as_str(),
            0xA6C7E1,
        );

        if let Some(selected) = prompt.locations.get(prompt.selected_index) {
            let destination_text = Self::trim_ascii_line(
                alloc::format!(
                    "{}: {}",
                    match prompt.kind {
                        SavePromptKind::Notepad => "Destino",
                        SavePromptKind::IdeExport => "Exportar en",
                        SavePromptKind::IdeLoad => "Cargar desde",
                    },
                    selected.path
                )
                .as_str(),
                56,
            );
            framebuffer::draw_text_5x7(
                (rect.x + 10).max(0) as usize,
                (rect.y + rect.height as i32 - 58).max(0) as usize,
                destination_text.as_str(),
                0xA9C6E1,
            );
        }

        framebuffer::draw_text_5x7(
            (rect.x + 10).max(0) as usize,
            (rect.y + rect.height as i32 - 44).max(0) as usize,
            instruction,
            0xA9C6E1,
        );

        let ok_rect = self.notepad_save_prompt_ok_rect();
        framebuffer::rect(
            ok_rect.x.max(0) as usize,
            ok_rect.y.max(0) as usize,
            ok_rect.width as usize,
            ok_rect.height as usize,
            0x2B5D45,
        );
        framebuffer::rect(
            ok_rect.x.max(0) as usize,
            ok_rect.y.max(0) as usize,
            ok_rect.width as usize,
            1,
            0x7CC2A0,
        );
        framebuffer::draw_text_5x7(
            (ok_rect.x
                + match prompt.kind {
                    SavePromptKind::Notepad => 26,
                    SavePromptKind::IdeExport => 11,
                    SavePromptKind::IdeLoad => 17,
                })
                .max(0) as usize,
            (ok_rect.y + 8).max(0) as usize,
            ok_label,
            0xF1FFF7,
        );

        let cancel_rect = self.notepad_save_prompt_cancel_rect();
        framebuffer::rect(
            cancel_rect.x.max(0) as usize,
            cancel_rect.y.max(0) as usize,
            cancel_rect.width as usize,
            cancel_rect.height as usize,
            0x4A3441,
        );
        framebuffer::rect(
            cancel_rect.x.max(0) as usize,
            cancel_rect.y.max(0) as usize,
            cancel_rect.width as usize,
            1,
            0x9F6D84,
        );
        framebuffer::draw_text_5x7(
            (cancel_rect.x + 11).max(0) as usize,
            (cancel_rect.y + 8).max(0) as usize,
            "Cancel",
            0xFFEAF3,
        );
    }

    fn set_desktop_item_custom_position_by_key(
        &mut self,
        cluster: u32,
        label: &str,
        x: i32,
        y: i32,
    ) {
        let min_x = DESKTOP_ITEMS_START_X.max(0);
        let min_y = self.desktop_items_dynamic_start_y().max(0);
        let max_x = (self.width as i32 - DESKTOP_ITEM_W as i32 - 8).max(min_x);
        let max_y = (self.taskbar.rect.y - DESKTOP_ITEM_H as i32 - 4).max(min_y);
        let clamped_x = x.clamp(min_x, max_x);
        let clamped_y = y.clamp(min_y, max_y);

        if let Some(entry) = self
            .desktop_icon_positions
            .iter_mut()
            .find(|entry| entry.cluster == cluster && entry.label.eq_ignore_ascii_case(label))
        {
            entry.x = clamped_x;
            entry.y = clamped_y;
            return;
        }

        self.desktop_icon_positions.push(DesktopIconPosition {
            cluster,
            label: String::from(label),
            x: clamped_x,
            y: clamped_y,
        });
    }

    fn update_desktop_drag(&mut self, mouse_x: i32, mouse_y: i32, left_down: bool) -> bool {
        let Some(mut drag) = self.desktop_drag.clone() else {
            return false;
        };

        if !left_down {
            self.desktop_drag = None;
            if drag.open_on_release && !drag.moved {
                let item = drag.item.clone();
                self.open_desktop_item(drag.source_dir_cluster, drag.source_dir_path.clone(), &item);
            }
            return true;
        }

        if !drag.moved {
            let moved_x = (mouse_x - drag.start_mouse_x).abs();
            let moved_y = (mouse_y - drag.start_mouse_y).abs();
            if moved_x >= DESKTOP_DRAG_OPEN_THRESHOLD || moved_y >= DESKTOP_DRAG_OPEN_THRESHOLD {
                drag.moved = true;
            }
        }

        let top_boundary = self.desktop_items_dynamic_start_y();
        let bottom_limit = self.taskbar.rect.y - DESKTOP_ITEM_H as i32 - 4;

        let mut next_rendered_x = mouse_x - drag.offset_x;
        let mut next_rendered_y = mouse_y - drag.offset_y;

        // Snap to grid
        let stride_x = DESKTOP_ITEM_W as i32 + DESKTOP_ITEM_GAP_X;
        let stride_y = DESKTOP_ITEM_H as i32 + DESKTOP_ITEM_GAP_Y;
        let min_x = DESKTOP_ITEMS_START_X.max(0);
        let max_x = (self.width as i32 - DESKTOP_ITEM_W as i32 - 8).max(min_x);
        let grid_x = min_x + ((next_rendered_x - min_x + stride_x / 2) / stride_x) * stride_x;
        let grid_y = top_boundary + ((next_rendered_y - top_boundary + stride_y / 2) / stride_y) * stride_y;

        next_rendered_x = grid_x.clamp(min_x, max_x);
        next_rendered_y = grid_y.clamp(top_boundary, bottom_limit);

        // Collision detection
        let mut collision = false;
        let canonical_x = next_rendered_x;
        let canonical_y = next_rendered_y + self.desktop_scroll;

        if let Some((_, _, items)) = self.desktop_surface_items() {
            for (idx, item) in items.iter().enumerate() {
                if Self::desktop_item_key_eq(drag.cluster, drag.label.as_str(), item) {
                    continue;
                }
                let Some((occupied_x, occupied_y)) =
                    self.desktop_item_canonical_position(idx, item)
                else {
                    continue;
                };
                if occupied_x == canonical_x && occupied_y == canonical_y {
                    collision = true;
                    break;
                }
            }
        }

        if !collision {
            self.set_desktop_item_custom_position_by_key(drag.cluster, drag.label.as_str(), canonical_x, canonical_y);
        }

        self.desktop_drag = Some(drag);
        true
    }

    fn explorer_item_is_zip(item: &ExplorerItem) -> bool {
        if !item.is_file() {
            return false;
        }
        Self::ascii_lower(item.label.trim()).ends_with(".zip")
    }

    fn explorer_item_is_installable_package(item: &ExplorerItem) -> bool {
        if !item.is_file() {
            return false;
        }
        let lower = Self::ascii_lower(item.label.trim());
        lower.ends_with(".rpx")
            || lower.ends_with(".zip")
            || lower.ends_with(".tar")
            || lower.ends_with(".tar.gz")
            || lower.ends_with(".tgz")
            || lower.ends_with(".deb")
            || lower.ends_with(".exe")
    }

    fn path_is_inside_apps(path: &str) -> bool {
        let mut normalized = String::new();
        for b in path.trim().bytes() {
            if b == b'\\' {
                normalized.push('/');
            } else {
                normalized.push((b as char).to_ascii_lowercase());
            }
        }

        if normalized.is_empty() {
            return false;
        }
        let trimmed = normalized.trim_matches('/');
        if trimmed.is_empty() {
            return false;
        }

        for component in trimmed.split('/') {
            if component == "apps" {
                return true;
            }
        }
        false
    }

    fn explorer_item_can_install_from_path(
        source_dir_path: Option<&str>,
        item: &ExplorerItem,
    ) -> bool {
        if !Self::explorer_item_is_installable_package(item) {
            return false;
        }
        let lower = Self::ascii_lower(item.label.trim());
        if lower.ends_with(".rpx")
            && source_dir_path
                .map(Self::path_is_inside_apps)
                .unwrap_or(false)
        {
            return false;
        }
        true
    }

    fn split_install_path(raw: &str) -> (Option<String>, &str) {
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            return (None, "");
        }
        let slash_pos = trimmed.rfind('/');
        let backslash_pos = trimmed.rfind('\\');
        let sep_pos = match (slash_pos, backslash_pos) {
            (Some(a), Some(b)) => Some(a.max(b)),
            (Some(a), None) => Some(a),
            (None, Some(b)) => Some(b),
            (None, None) => None,
        };
        if let Some(pos) = sep_pos {
            let dir = trimmed[..pos].trim();
            let name = trimmed[pos.saturating_add(1)..].trim();
            let dir_norm = dir.replace('\\', "/");
            let dir_opt = if dir_norm.is_empty() {
                None
            } else {
                Some(dir_norm)
            };
            return (dir_opt, name);
        }
        (None, trimmed)
    }

    fn launch_install_from_context(
        &mut self,
        source_dir_cluster: u32,
        source_dir_path: Option<&str>,
        target: &ExplorerItem,
    ) {
        let package = target.label.trim();
        if package.is_empty() {
            return;
        }

        let term_id = self
            .windows
            .iter()
            .find(|w| w.is_terminal())
            .map(|w| w.id)
            .unwrap_or_else(|| self.create_window("Terminal Shell", 100, 100, 800, 500));

        let mut resolved_cluster = source_dir_cluster;
        if resolved_cluster < 2 {
            if let Some(path) = source_dir_path {
                let fat = unsafe { &mut crate::fat32::GLOBAL_FAT };
                if let Some(cluster) =
                    Self::resolve_directory_cluster_from_explorer_path(fat, path)
                {
                    resolved_cluster = cluster;
                }
            }
        }

        if let Some(term) = self.windows.iter_mut().find(|w| w.id == term_id) {
            if resolved_cluster >= 2 {
                term.current_dir_cluster = resolved_cluster;
            }

            let mut path_text = source_dir_path
                .map(|v| String::from(v.trim()))
                .unwrap_or_else(|| String::from("REDUX/"));
            if path_text.is_empty() {
                path_text = String::from("REDUX/");
            }
            if !path_text.ends_with('/') {
                path_text.push('/');
            }
            term.current_path = path_text;
            term.add_output(alloc::format!("GUI: install {}", package).as_str());
            term.render_terminal();
        }

        let mut pending_entry = crate::fs::DirEntry::empty();
        pending_entry.valid = true;
        pending_entry.file_type = crate::fs::FileType::File;
        pending_entry.cluster = target.cluster;
        pending_entry.size = target.size;
        pending_entry.set_display_name(package);
        let pending_install = PendingInstallItem {
            entry: pending_entry,
            dir_cluster: resolved_cluster,
        };
        self.enqueue_terminal_command(
            term_id,
            alloc::format!("install {}", package).as_str(),
            Some(pending_install),
        );
    }

    fn explorer_directory_can_delete(source_dir_cluster: u32, item: &ExplorerItem) -> bool {
        if item.kind != ExplorerItemKind::Directory {
            return false;
        }

        let root_cluster = unsafe { crate::fat32::GLOBAL_FAT.root_cluster };
        if source_dir_cluster == root_cluster
            && Self::is_quick_access_shortcut_name(item.label.as_str())
        {
            return false;
        }

        true
    }

    fn explorer_context_item_count_for_kind(
        kind: ExplorerContextMenuKind,
        target_item: Option<&ExplorerItem>,
        source_dir_path: Option<&str>,
        source_dir_cluster: u32,
        selection_count: usize,
    ) -> usize {
        let is_trash_dir = {
            let fat = unsafe { &mut crate::fat32::GLOBAL_FAT };
            fat.resolve_path(fat.root_cluster, "TRASH/").map(|(_, c)| c).unwrap_or(0) == source_dir_cluster && source_dir_cluster >= 2
        };

        if is_trash_dir {
            return 2; // Restaurar + Eliminar
        }

        match kind {
            ExplorerContextMenuKind::FileItem => {
                let mut count = 6; // Copiar, Cortar, Renombrar, Eliminar, Favoritos, Fijar en barra
                if let Some(item) = target_item {
                    if selection_count <= 1 {
                        if Self::explorer_item_is_zip(item) {
                            count += 1; // Extraer aqui
                        }
                        if Self::explorer_item_can_install_from_path(source_dir_path, item) {
                            count += 1; // Instalar paquete
                        }
                    }
                }
                count
            }
            ExplorerContextMenuKind::DirectoryItem => {
                if let Some(item) = target_item {
                    if item.kind == ExplorerItemKind::ShortcutRecycleBin {
                        return 1; // Solo "Vaciar Papelera"
                    }
                }
                let mut count = 5; // Copiar carpeta, Cortar carpeta, Renombrar carpeta, Favoritos, Fijar en barra
                if let Some(item) = target_item {
                    if Self::explorer_directory_can_delete(source_dir_cluster, item) {
                        count += 1; // Eliminar carpeta
                    }
                }
                count
            }
            ExplorerContextMenuKind::PasteArea => 1,
            ExplorerContextMenuKind::DesktopArea => 1,
            ExplorerContextMenuKind::AppItem => 3, // Escritorio + Favoritos + Fijar en barra
        }
    }

    fn explorer_context_menu_item_count(&self, menu: &ExplorerContextMenuState) -> usize {
        if menu.kind == ExplorerContextMenuKind::DesktopArea {
            return if menu.show_paste { 3 } else { 2 };
        }
        if menu.kind == ExplorerContextMenuKind::PasteArea {
            return if menu.show_paste { 3 } else { 2 };
        }
        let mut count = Self::explorer_context_item_count_for_kind(
            menu.kind,
            menu.target_item.as_ref(),
            self.windows
                .iter()
                .find(|w| w.id == menu.win_id)
                .map(|w| w.explorer_path.as_str()),
            menu.source_dir_cluster,
            menu.selection_count,
        );
        if menu.show_paste
            && (menu.kind == ExplorerContextMenuKind::FileItem
                || menu.kind == ExplorerContextMenuKind::DirectoryItem)
        {
            count += 1;
        }
        count
    }

    fn explorer_context_menu_height(item_count: usize) -> u32 {
        (item_count as u32).saturating_mul(EXPLORER_CONTEXT_MENU_ITEM_H)
            + (EXPLORER_CONTEXT_MENU_PADDING as u32).saturating_mul(2)
    }

    fn clamp_explorer_context_menu_origin(&self, x: i32, y: i32, item_count: usize) -> (i32, i32) {
        let menu_h = Self::explorer_context_menu_height(item_count) as i32;
        let max_x = (self.width as i32 - EXPLORER_CONTEXT_MENU_W as i32).max(0);
        let max_y = (self.taskbar.rect.y - menu_h).max(0);
        (x.clamp(0, max_x), y.clamp(0, max_y))
    }

    fn explorer_context_menu_rect(&self, menu: &ExplorerContextMenuState) -> Rect {
        let item_count = self.explorer_context_menu_item_count(menu);
        Rect::new(
            menu.x,
            menu.y,
            EXPLORER_CONTEXT_MENU_W,
            Self::explorer_context_menu_height(item_count),
        )
    }

    fn explorer_context_menu_item_rect(&self, menu: &ExplorerContextMenuState, index: usize) -> Rect {
        let menu_rect = self.explorer_context_menu_rect(menu);
        Rect::new(
            menu_rect.x + EXPLORER_CONTEXT_MENU_PADDING,
            menu_rect.y
                + EXPLORER_CONTEXT_MENU_PADDING
                + (index as i32 * EXPLORER_CONTEXT_MENU_ITEM_H as i32),
            menu_rect
                .width
                .saturating_sub((EXPLORER_CONTEXT_MENU_PADDING as u32).saturating_mul(2)),
            EXPLORER_CONTEXT_MENU_ITEM_H,
        )
    }

    fn ide_context_menu_item_count(menu: &IdeContextMenuState) -> usize {
        2 + (menu.show_copy as usize) + (menu.show_cut as usize) + (menu.show_paste as usize)
    }

    fn ide_context_menu_action_at(menu: &IdeContextMenuState, index: usize) -> Option<IdeContextMenuAction> {
        let mut cursor = 0usize;
        if index == cursor {
            return Some(IdeContextMenuAction::Undo);
        }
        cursor += 1;
        if index == cursor {
            return Some(IdeContextMenuAction::Redo);
        }
        cursor += 1;

        if menu.show_copy {
            if index == cursor {
                return Some(IdeContextMenuAction::Copy);
            }
            cursor += 1;
        }
        if menu.show_cut {
            if index == cursor {
                return Some(IdeContextMenuAction::Cut);
            }
            cursor += 1;
        }
        if menu.show_paste && index == cursor {
            return Some(IdeContextMenuAction::Paste);
        }
        None
    }

    fn ide_context_menu_action_enabled(menu: &IdeContextMenuState, action: IdeContextMenuAction) -> bool {
        match action {
            IdeContextMenuAction::Undo => menu.can_undo,
            IdeContextMenuAction::Redo => menu.can_redo,
            IdeContextMenuAction::Copy => menu.show_copy,
            IdeContextMenuAction::Cut => menu.show_cut,
            IdeContextMenuAction::Paste => menu.show_paste,
        }
    }

    fn ide_context_menu_height(menu: &IdeContextMenuState) -> u32 {
        (Self::ide_context_menu_item_count(menu) as u32).saturating_mul(IDE_CONTEXT_MENU_ITEM_H)
            + (IDE_CONTEXT_MENU_PADDING as u32).saturating_mul(2)
    }

    fn clamp_ide_context_menu_origin(&self, x: i32, y: i32, item_count: usize) -> (i32, i32) {
        let menu_h = (item_count as i32 * IDE_CONTEXT_MENU_ITEM_H as i32)
            + (IDE_CONTEXT_MENU_PADDING * 2);
        let max_x = (self.width as i32 - IDE_CONTEXT_MENU_W as i32).max(0);
        let max_y = (self.taskbar.rect.y - menu_h).max(0);
        (x.clamp(0, max_x), y.clamp(0, max_y))
    }

    fn ide_context_menu_rect(&self, menu: &IdeContextMenuState) -> Rect {
        Rect::new(
            menu.x,
            menu.y,
            IDE_CONTEXT_MENU_W,
            Self::ide_context_menu_height(menu),
        )
    }

    fn ide_context_menu_item_rect(&self, menu: &IdeContextMenuState, index: usize) -> Rect {
        let menu_rect = self.ide_context_menu_rect(menu);
        Rect::new(
            menu_rect.x + IDE_CONTEXT_MENU_PADDING,
            menu_rect.y + IDE_CONTEXT_MENU_PADDING + (index as i32 * IDE_CONTEXT_MENU_ITEM_H as i32),
            menu_rect
                .width
                .saturating_sub((IDE_CONTEXT_MENU_PADDING as u32).saturating_mul(2)),
            IDE_CONTEXT_MENU_ITEM_H,
        )
    }

    fn draw_ide_context_menu_overlay(&mut self) {
        let Some(menu) = self.ide_context_menu.as_ref() else {
            return;
        };
        let item_count = Self::ide_context_menu_item_count(menu);
        if item_count == 0 {
            return;
        }
        let menu_rect = self.ide_context_menu_rect(menu);
        framebuffer::rect(
            menu_rect.x.max(0) as usize,
            menu_rect.y.max(0) as usize,
            menu_rect.width as usize,
            menu_rect.height as usize,
            0x1D2D3D,
        );
        framebuffer::rect(
            menu_rect.x.max(0) as usize,
            menu_rect.y.max(0) as usize,
            menu_rect.width as usize,
            1,
            0x5F85A8,
        );
        framebuffer::rect(
            menu_rect.x.max(0) as usize,
            (menu_rect.y + menu_rect.height as i32 - 1).max(0) as usize,
            menu_rect.width as usize,
            1,
            0x0F1A27,
        );

        for idx in 0..item_count {
            let item_rect = self.ide_context_menu_item_rect(menu, idx);
            let Some(action) = Self::ide_context_menu_action_at(menu, idx) else {
                continue;
            };
            let enabled = Self::ide_context_menu_action_enabled(menu, action);
            let (label, mut bg, mut fg) = match action {
                IdeContextMenuAction::Undo => ("Regresar", 0x36596Fu32, 0xEAF6FFu32),
                IdeContextMenuAction::Redo => ("Rehacer", 0x36596Fu32, 0xEAF6FFu32),
                IdeContextMenuAction::Copy => ("Copiar", 0x2B5D45u32, 0xEAF6FFu32),
                IdeContextMenuAction::Cut => ("Cortar", 0x6A3A3Au32, 0xFFEDEDu32),
                IdeContextMenuAction::Paste => ("Pegar", 0x2F566Fu32, 0xEAF6FFu32),
            };
            if !enabled {
                bg = 0x2B3440;
                fg = 0x9FB2C4;
            }
            framebuffer::rect(
                item_rect.x.max(0) as usize,
                item_rect.y.max(0) as usize,
                item_rect.width as usize,
                item_rect.height as usize,
                bg,
            );
            framebuffer::draw_text_5x7(
                (item_rect.x + 8).max(0) as usize,
                (item_rect.y + 8).max(0) as usize,
                label,
                fg,
            );
        }
    }

    fn draw_pinned_context_menu_overlay(&mut self) {
        let Some((_, menu_x, menu_y)) = self.pinned_context_menu_index else {
            return;
        };
        let menu_w = 160usize;
        let menu_h = 28usize;
        let x = menu_x.max(0) as usize;
        let y = (menu_y - menu_h as i32).max(0) as usize;
        // Background
        framebuffer::rect(x, y, menu_w, menu_h, 0x1D2D3D);
        // Top border
        framebuffer::rect(x, y, menu_w, 1, 0x5F85A8);
        // Bottom border
        framebuffer::rect(x, y + menu_h - 1, menu_w, 1, 0x0F1A27);
        // Item bg
        framebuffer::rect(x + 1, y + 1, menu_w - 2, menu_h - 2, 0x6A2D2D);
        // Text
        framebuffer::draw_text_5x7(x + 8, y + 9, "Desfijar de barra", 0xFFE5E5);
    }

    fn draw_explorer_context_menu_overlay(&mut self) {
        let Some(menu) = self.explorer_context_menu.as_ref() else {
            return;
        };

        let menu_rect = self.explorer_context_menu_rect(menu);
        framebuffer::rect(
            menu_rect.x.max(0) as usize,
            menu_rect.y.max(0) as usize,
            menu_rect.width as usize,
            menu_rect.height as usize,
            0x1D2D3D,
        );
        framebuffer::rect(
            menu_rect.x.max(0) as usize,
            menu_rect.y.max(0) as usize,
            menu_rect.width as usize,
            1,
            0x5F85A8,
        );
        framebuffer::rect(
            menu_rect.x.max(0) as usize,
            (menu_rect.y + menu_rect.height as i32 - 1).max(0) as usize,
            menu_rect.width as usize,
            1,
            0x0F1A27,
        );

        let item_count = self.explorer_context_menu_item_count(menu);
        let is_trash_dir = {
            let fat = unsafe { &mut crate::fat32::GLOBAL_FAT };
            fat.resolve_path(fat.root_cluster, "TRASH/").map(|(_, c)| c).unwrap_or(0) == menu.source_dir_cluster && menu.source_dir_cluster >= 2
        };

        for idx in 0..item_count {
            let item_rect = self.explorer_context_menu_item_rect(menu, idx);
            let mut label = "";
            let mut bg = 0x294259u32;
            let mut fg = 0xEAF6FFu32;

            if is_trash_dir {
                if idx == 0 {
                    label = "Restaurar";
                    bg = 0x2B5D45;
                } else if idx == 1 {
                    label = "Eliminar";
                    bg = 0x6A2D2D;
                    fg = 0xFFE5E5;
                }
            } else {
                match menu.kind {
                    ExplorerContextMenuKind::FileItem => {
                        let is_zip = menu
                            .target_item
                            .as_ref()
                            .map(Self::explorer_item_is_zip)
                            .unwrap_or(false);
                        let source_dir_path = self
                            .windows
                            .iter()
                            .find(|w| w.id == menu.win_id)
                            .map(|w| w.explorer_path.as_str());
                        let can_install = menu
                            .target_item
                            .as_ref()
                            .map(|item| Self::explorer_item_can_install_from_path(source_dir_path, item))
                            .unwrap_or(false);
                        if idx == 0 {
                            label = "Copiar";
                            bg = 0x2B5D45;
                        } else if idx == 1 {
                            label = "Cortar";
                            bg = 0x6A3A3A;
                        } else if idx == 2 {
                            label = "Renombrar";
                            bg = 0x36596F;
                        } else if idx == 3 {
                            label = "Eliminar";
                            bg = 0x6A2D2D;
                            fg = 0xFFE5E5;
                        }

                        let mut extra_idx = if menu.selection_count <= 1 {
                            let mut base = 4usize;
                            if is_zip {
                                if idx == base {
                                    label = "Extraer aqui";
                                    bg = 0x36596F;
                                }
                                base += 1;
                            }
                            if can_install {
                                if idx == base {
                                    label = "Instalar";
                                    bg = 0x3F5A2C;
                                    fg = 0xF1FFE6;
                                }
                                base += 1;
                            }
                            base
                        } else {
                            4usize
                        };

                        if menu.show_paste && idx == extra_idx {
                            if let Some(clip) = self.explorer_clipboard.as_ref() {
                                if clip.mode == ExplorerClipboardMode::Cut {
                                    label = "Pegar (mover)";
                                    bg = 0x5A4630;
                                    fg = 0xFFF2DE;
                                } else {
                                    label = "Pegar";
                                    bg = 0x2F566F;
                                }
                            } else {
                                label = "Pegar";
                                bg = 0x2B3440;
                                fg = 0x9FB2C4;
                            }
                        }
                        if item_count >= 2 && idx == item_count - 2 {
                            label = "Guardar en favoritos";
                            bg = 0x355B3A;
                            fg = 0xE8FFE9;
                        } else if idx == item_count - 1 {
                            label = "Fijar en barra";
                            bg = 0x4A3366;
                        }
                    }
                    ExplorerContextMenuKind::DirectoryItem => {
                        let is_trash_shortcut = menu.target_item.as_ref().map(|i| i.kind == ExplorerItemKind::ShortcutRecycleBin).unwrap_or(false);
                        if is_trash_shortcut {
                            if idx == 0 {
                                label = "Vaciar Papelera";
                                bg = 0x6A2D2D;
                                fg = 0xFFE5E5;
                            }
                        } else {
                            let can_delete = menu
                                .target_item
                                .as_ref()
                                .map(|item| Self::explorer_directory_can_delete(menu.source_dir_cluster, item))
                                .unwrap_or(false);
                            if idx == 0 {
                                label = "Copiar carpeta";
                                bg = 0x2B5D45;
                            } else if idx == 1 {
                                label = "Cortar carpeta";
                                bg = 0x6A3A3A;
                            } else if idx == 2 {
                                label = "Renombrar carpeta";
                                bg = 0x36596F;
                            } else if idx == 3 && can_delete {
                                label = "Eliminar carpeta";
                                bg = 0x6A2D2D;
                                fg = 0xFFE5E5;
                            } else {
                                let extra_idx = if can_delete { 4usize } else { 3usize };
                                if menu.show_paste && idx == extra_idx {
                                    if let Some(clip) = self.explorer_clipboard.as_ref() {
                                        if clip.mode == ExplorerClipboardMode::Cut {
                                            label = "Pegar (mover)";
                                            bg = 0x5A4630;
                                            fg = 0xFFF2DE;
                                        } else {
                                            label = "Pegar";
                                            bg = 0x2F566F;
                                        }
                                    } else {
                                        label = "Pegar";
                                        bg = 0x2B3440;
                                        fg = 0x9FB2C4;
                                    }
                                }
                            }
                            if item_count >= 2 && idx == item_count - 2 {
                                label = "Guardar en favoritos";
                                bg = 0x355B3A;
                                fg = 0xE8FFE9;
                            } else if idx == item_count - 1 {
                                label = "Fijar en barra";
                                bg = 0x4A3366;
                            }
                        }
                    }
                    ExplorerContextMenuKind::PasteArea => {
                        if idx == 0 {
                            label = "Crear carpeta";
                            bg = 0x2D4A5F;
                        } else if idx == 1 {
                            label = "Crear nota";
                            bg = 0x3A4D66;
                        } else if idx == 2 && menu.show_paste {
                            if let Some(clip) = self.explorer_clipboard.as_ref() {
                                if clip.mode == ExplorerClipboardMode::Cut {
                                    label = "Pegar (mover)";
                                    bg = 0x5A4630;
                                    fg = 0xFFF2DE;
                                } else {
                                    label = "Pegar";
                                    bg = 0x2F566F;
                                }
                            } else {
                                label = "Pegar";
                                bg = 0x2B3440;
                                fg = 0x9FB2C4;
                            }
                        }
                    }
                    ExplorerContextMenuKind::DesktopArea => {
                        if idx == 0 {
                            label = "Crear carpeta";
                            bg = 0x2D4A5F;
                        } else if idx == 1 {
                            label = "Crear nota";
                            bg = 0x3A4D66;
                        } else if idx == 2 && menu.show_paste {
                            if let Some(clip) = self.explorer_clipboard.as_ref() {
                                if clip.mode == ExplorerClipboardMode::Cut {
                                    label = "Pegar (mover)";
                                    bg = 0x5A4630;
                                    fg = 0xFFF2DE;
                                } else {
                                    label = "Pegar";
                                    bg = 0x2F566F;
                                }
                            } else {
                                label = "Pegar";
                                bg = 0x2B3440;
                                fg = 0x9FB2C4;
                            }
                        }
                    }
                    ExplorerContextMenuKind::AppItem => {
                        if idx == 0 {
                            label = "Añadir al escritorio";
                            bg = 0x36596F;
                        } else if idx == 1 {
                            label = "Guardar en favoritos";
                            bg = 0x355B3A;
                            fg = 0xE8FFE9;
                        } else if idx == 2 {
                            label = "Fijar en barra";
                            bg = 0x4A3366;
                        }
                    }
                }
            }

            framebuffer::rect(
                item_rect.x.max(0) as usize,
                item_rect.y.max(0) as usize,
                item_rect.width as usize,
                item_rect.height as usize,
                bg,
            );
            framebuffer::draw_text_5x7(
                (item_rect.x + 8).max(0) as usize,
                (item_rect.y + 8).max(0) as usize,
                label,
                fg,
            );
        }
    }

