                        out.push(String::from("  linux guest rootfs <ruta_linux>"));
                        out.push(String::from("  linux guest share <ruta_linux>"));
                        out.push(String::from("  linux guest prefix <tag:>"));
                        out.push(String::from("  linux guest map <ruta>"));
